previewCss:
.darma-loader-stepped-progress {
  display: inline-flex;
  gap: 8px;
  color: #6366f1;
}
.darma-loader-stepped-progress i {
  width: 18px;
  height: 18px;
  border-radius: 7px;
  background: currentColor;
  opacity: 0.25;
  animation: darma-loader-stepped-progress-step 1.2s ease-in-out infinite;
}
.darma-loader-stepped-progress i:nth-child(2) { animation-delay: 0.15s; }
.darma-loader-stepped-progress i:nth-child(3) { animation-delay: 0.3s; }
.darma-loader-stepped-progress i:nth-child(4) { animation-delay: 0.45s; }
@keyframes darma-loader-stepped-progress-step {
  0%, 100% { opacity: 0.22; transform: translateY(0); }
  45% { opacity: 1; transform: translateY(-6px); }
}

